	const acctRes = await client.query('SELECT doc FROM accounts WHERE account_id = $1', [order.accountId]);
	const account = acctRes.rows[0]?.doc;
	const invRes = await client.query("SELECT doc FROM invoices WHERE doc->>'orderId' = $1", [orderId]);
	const invoice = invRes.rows[0]?.doc;
	const shipRes = await client.query("SELECT doc FROM shipments WHERE doc->>'orderId' = $1", [orderId]);
	const shipment = shipRes.rows[0]?.doc;
	return {
		orderId: order.orderId,
		status: order.status,
		totalCents: order.totalCents,
		currency: order.currency,
		lineItems: order.lineItems || [],
		accountName: account?.name,
		accountTier: account?.tier,
		invoiceStatus: invoice?.status,
		invoiceAmountCents: invoice?.amountCents,
		shipmentStatus: shipment?.status,
		carrier: shipment?.carrier,
	};
}

